const config = $('⚙️ Load Config').item.json;
const tz = config.CONTENT_DAY_TIMEZONE || config.TIMEZONE || 'UTC';
const today = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const rows = $input.all().map(i => i.json);
const dateKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'date') || 'date';
const valid = rows.filter(r => (r[dateKey] || r.date || '').toString().slice(0, 10) === today);
if (valid.length === 0) return [{ json: { noPostToday: true } }];
const row = valid[valid.length - 1];
return [{ json: { ...row, noPostToday: false } }];

// Prepare audio jobs for all language versions
const allPosts = $input.all();

// Voice configuration per language
const voiceConfig = {
  'en': { voice_id: 'EXAVITQu4vr4xnSDxMaL', name: 'Sarah', gender: 'female', provider: 'elevenlabs' },
  'es': { voice_id: 'XrExE9yKIg1WjnnlVkGX', name: 'Matilda', gender: 'female', provider: 'elevenlabs' },
  'pt-BR': { voice_id: 'GBv7mTt0atIp3Br8iCZE', name: 'Ricardo', gender: 'male', provider: 'elevenlabs' },
  'de': { voice_id: 'iP95p4xoKVk53GoZ742B', name: 'Klaus', gender: 'male', provider: 'elevenlabs' },
  'fr': { voice_id: 'zrHiDhphv9ZnVXBqCLjz', name: 'Charlotte', gender: 'female', provider: 'elevenlabs' },
  'hi': { voice_id: 'hi-IN-Neural2-A', name: 'Aditi', gender: 'female', provider: 'google' },
  'id': { voice_id: 'id-ID-Standard-B', name: 'Siti', gender: 'female', provider: 'google' },
  'ar': { voice_id: 'ar-XA-Standard-A', name: 'Layla', gender: 'female', provider: 'google' },
  'ja': { voice_id: 'ja-JP-Neural2-B', name: 'Yuki', gender: 'female', provider: 'google' }
};

return allPosts.map(post => {
  const lang = post.json['Language']?.toLowerCase() || 'en';
  const langCode = lang.includes('spanish') ? 'es' : 
                   lang.includes('portuguese') ? 'pt-BR' : 
                   lang.includes('german') ? 'de' : 
                   lang.includes('french') ? 'fr' : 
                   lang.includes('hindi') ? 'hi' : 
                   lang.includes('indonesian') ? 'id' : 
                   lang.includes('arabic') ? 'ar' : 
                   lang.includes('japanese') ? 'ja' : 'en';

  return {
    json: {
      title: post.json['Translated Title'] || post.json['Title'],
      url: post.json['URL'],
      language: langCode,
      language_name: post.json['Language'] || 'English',
      voice_config: voiceConfig[langCode] || voiceConfig['en'],
      content_preview: (post.json['Translated Title'] || '').substring(0, 200)
    }
  };
});

const raw = $input.first().json.response || '';
const voiceConfig = $('Configure Voice Settings').item.json.voice_config;
const langData = $('Configure Voice Settings').item.json;

let audioScript;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  audioScript = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  audioScript = {
    podcast_title: langData.title,
    podcast_script: 'Welcome to HowTo-Genie Podcast. ' + langData.content_preview,
    estimated_duration: '10 minutes',
    word_count: 1500,
    parse_error: e.message
  };
}

// Clean script for TTS (remove stage directions)
const ttsScript = audioScript.podcast_script
  .replace(/\[PAUSE\]/g, '... ')
  .replace(/\[EMPHASIS[^\]]*\]/g, '')
  .replace(/\[.*?\]/g, '')
  .trim();

return [{
  json: {
    ...langData,
    podcast_title: audioScript.podcast_title,
    podcast_script: audioScript.podcast_script,
    tts_script: ttsScript,
    estimated_duration: audioScript.estimated_duration,
    word_count: audioScript.word_count,
    chapters: audioScript.chapters || [],
    show_notes: audioScript.show_notes || '',
    keywords: audioScript.keywords || [],
    affiliate_mentions: audioScript.affiliate_mentions || [],
    voice_provider: voiceConfig.provider,
    voice_id: voiceConfig.voice_id,
    voice_name: voiceConfig.name
  }
}];

// Extract audio data and prepare for distribution
const audioData = $input.first().json;
const scriptData = $('Parse Audio Script').item.json;

let audioFile;
let audioFormat;

if (audioData.data) {
  // ElevenLabs returns binary audio
  audioFile = audioData.data;
  audioFormat = 'mp3';
} else if (audioData.audioContent) {
  // Google TTS returns base64
  audioFile = Buffer.from(audioData.audioContent, 'base64');
  audioFormat = 'mp3';
} else {
  audioFile = null;
}

const fileName = `howtogenie_${scriptData.language}_${Date.now()}.mp3`;

return [{
  json: {
    ...scriptData,
    audio_file_name: fileName,
    audio_format: audioFormat,
    audio_size_kb: audioFile ? Math.round(audioFile.length / 1024) : 0,
    audio_ready: !!audioFile,
    generated_at: new Date().toISOString()
  },
  binary: audioFile ? {
    data: audioFile,
    fileName: fileName,
    mimeType: 'audio/mpeg'
  } : undefined
}];

// Build podcast RSS feed item
const audio = $input.first().json;
const publicUrl = `https://storage.googleapis.com/howtogenie-audio/${audio.audio_file_name}`;

const rssItem = `
<item>
  <title>${audio.podcast_title}</title>
  <link>${audio.url}</link>
  <description><![CDATA[${audio.show_notes}]]></description>
  <enclosure url="${publicUrl}" length="${audio.audio_size_kb * 1024}" type="audio/mpeg" />
  <guid isPermaLink="false">${audio.audio_file_name}</guid>
  <pubDate>${new Date(audio.generated_at).toUTCString()}</pubDate>
  <itunes:duration>${audio.estimated_duration}</itunes:duration>
  <itunes:keywords>${audio.keywords.join(', ')}</itunes:keywords>
  <itunes:explicit>no</itunes:explicit>
</item>
`;

return [{
  json: {
    ...audio,
    audio_url: publicUrl,
    rss_item: rssItem,
    podcast_platforms: [
      { name: 'Spotify', status: 'ready' },
      { name: 'Apple Podcasts', status: 'ready' },
      { name: 'Google Podcasts', status: 'ready' },
      { name: 'YouTube Music', status: 'ready' },
      { name: 'Amazon Music', status: 'ready' }
    ]
  }
}];

// Create WhatsApp Voice Note version (60 seconds max)
const fullScript = $('Parse Audio Script').item.json.tts_script;
const words = fullScript.split(' ');
const targetWords = 150; // ~60 seconds at normal pace

const shortScript = words.slice(0, targetWords).join(' ') + 
  '... For the complete guide, visit the link in bio.';

return [{
  json: {
    ...$$('Parse Audio Script').item.json,
    voice_note_script: shortScript,
    voice_note_duration: '60 seconds',
    platform: 'WhatsApp/Telegram'
  }
}];
